/// Filesystem node type.
#[repr(u8)]
#[derive(Debug, Clone, Copy, Eq, PartialEq, Default, TryFromPrimitive)]
pub enum NodeType {
    #[default]
    Unknown = 0,
    Fifo = 0o1,
    CharacterDevice = 0o2,
    Directory = 0o4,
    BlockDevice = 0o6,
    RegularFile = 0o10,
    Symlink = 0o12,
    Socket = 0o14,
}

bitflags::bitflags! {
    /// Inode permission mode.
    #[derive(Debug, Clone, Copy)]
    pub struct NodePermission: u16 {
        /// Set process effective user ID on execution.
        const SET_OWNER = 0o4000;
        /// Set process effective group ID on execution.
        const SET_GROUP = 0o2000;
        /// Sticky bit, only owner can delete or rename the file.
        const STICKY = 0o1000;

        /// Owner has read permission.
        const OWNER_READ = 0o400;
        /// Owner has write permission.
        const OWNER_WRITE = 0o200;
        /// Owner has execute permission.
        const OWNER_EXEC = 0o100;

        /// Group has read permission.
        const GROUP_READ = 0o40;
        /// Group has write permission.
        const GROUP_WRITE = 0o20;
        /// Group has execute permission.
        const GROUP_EXEC = 0o10;

        /// Others have read permission.
        const OTHER_READ = 0o4;
        /// Others have write permission.
        const OTHER_WRITE = 0o2;
        /// Others have execute permission.
        const OTHER_EXEC = 0o1;
    }
}
impl Default for NodePermission {
    fn default() -> Self {
        Self::from_bits_truncate(0o666)
    }
}

/// Filesystem node metadata.
#[derive(Clone, Debug, Default)]
pub struct Metadata {
    /// ID of device containing file
    pub device: u64,
    /// Inode number
    pub inode: u64,
    /// Number of hard links
    pub n_link: u64,
    /// Permission mode
