pub fn check_signals(tf: &mut TrapFrame, restore_blocked: Option<SignalSet>) -> bool {
    let signal = &current_thread_data().signal;
    let Some((sig, os_action)) = signal.check_signals(tf, restore_blocked) else {
        return false;
    };

    let signo = sig.signo();
    const CORE_DUMP: u32 = 0x80;
    match os_action {
        SignalOSAction::Terminate => {
            debug!(
                "[signal] handle signal: signo: {:?}, code: {}, os_action: Terminate",
                signo,
                sig.code()
            );
            sys_exit_impl(0, signo as u32, true);
        }
        SignalOSAction::CoreDump => {
            // TODO: implement core dump
            debug!(
                "[signal] handle signal: signo: {:?}, code: {}, os_action: CoreDump",
                signo,
                sig.code()
            );
            sys_exit_impl(0, CORE_DUMP + signo as u32, true);
        }
        SignalOSAction::Stop => {
            // TODO: implement stop
            debug!(
                "[signal] handle signal: signo: {:?}, code: {}, os_action: Stop",
                signo,
                sig.code()
            );
            sys_exit_impl(0, signo as u32, true);
        }
        SignalOSAction::Continue => {
            // TODO: implement continue
        }
        SignalOSAction::Handler => {
            // do nothing
        }
    }
    true
}

#[register_trap_handler(POST_TRAP)]
fn post_trap_callback(tf: &mut TrapFrame, from_user: bool) {
    if !from_user {
        return;
    }

    check_signals(tf, None);
}

fn check_sigset_size(size: usize) -> LinuxResult<()> {
    if size != size_of::<SignalSet>() {
        return Err(LinuxError::EINVAL);
    }
    Ok(())
}

fn parse_signo(signo: u32) -> LinuxResult<Signo> {
    Signo::from_repr(signo as u8).ok_or(LinuxError::EINVAL)
}

#[repr(C)]
#[derive(Clone, Copy)]
pub struct KernelSigAction {
    handler: __kernel_sighandler_t,
    flags: c_ulong,
    restorer: __sigrestore_t,
    mask: kernel_sigset_t,
}

fn signal_action_from_kernel(value: KernelSigAction) -> LinuxResult<SignalAction> {
    let Some(flags) = SignalActionFlags::from_bits(value.flags) else {
        warn!("unrecognized signal flags: {}", value.flags);
        return Err(LinuxError::EINVAL);
    };

    let disposition = match value.handler {
        None => SignalDisposition::Default,
        Some(h) if h as usize == 1 => SignalDisposition::Ignore,
        Some(h) => SignalDisposition::Handler(h),
    };

    let restorer = if flags.contains(SignalActionFlags::RESTORER) {
        value.restorer
    } else {
        None
    };

    Ok(SignalAction {
        flags,
        mask: value.mask.into(),
        disposition,
        restorer,
    })
}

fn signal_action_to_kernel(action: &SignalAction, dest: &mut KernelSigAction) {
    dest.flags = action.flags.bits();
    dest.restorer = action.restorer;
    action.mask.to_ctype(&mut dest.mask);
    dest.handler = match &action.disposition {
        SignalDisposition::Default => None,
        SignalDisposition::Ignore => sig_ign(),
        SignalDisposition::Handler(handler) => Some(*handler),
    };
}

pub fn sys_rt_sigprocmask(
    how: i32,
    set: UserConstPtr<SignalSet>,
    oldset: UserPtr<SignalSet>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;

    current_thread_data()
        .signal
        .with_blocked_mut::<LinuxResult<_>>(|blocked| {
            if let Some(oldset) = oldset.nullable(UserPtr::get)? {
                unsafe { *oldset = *blocked };
            }

            if let Some(set) = set.nullable(UserConstPtr::get)? {
                let set = unsafe { *set };
                match how as u32 {
                    SIG_BLOCK => *blocked |= set,
                    SIG_UNBLOCK => *blocked &= !set,
                    SIG_SETMASK => *blocked = set,
                    _ => return Err(LinuxError::EINVAL),
                }
            }
            Ok(())
        })?;

    Ok(0)
}

pub fn sys_rt_sigaction(
    signo: u32,
    act: UserConstPtr<KernelSigAction>,
    oldact: UserPtr<KernelSigAction>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;

    let signo = parse_signo(signo)?;
    if matches!(signo, Signo::SIGKILL | Signo::SIGSTOP) {
        return Err(LinuxError::EINVAL);
    }

    let signal = &current_process_data().signal;
    let mut actions = signal.actions.lock();
    if let Some(oldact) = oldact.nullable(UserPtr::get)? {
        signal_action_to_kernel(&actions[signo], unsafe { &mut *oldact });
    }
    if let Some(act) = act.nullable(UserConstPtr::get)? {
        actions[signo] = signal_action_from_kernel(unsafe { *act })?;
    }
    Ok(0)
}

pub fn sys_rt_sigpending(set: UserPtr<SignalSet>, sigsetsize: usize) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;
    unsafe {
        *set.get()? = current_thread_data().signal.pending();
    }
    Ok(0)
}

pub fn send_signal_thread(tid: Pid, sig: SignalInfo) -> LinuxResult<()> {
    info!("Send signal {:?} to thread {}", sig.signo(), tid);
    let thread_data = get_thread_data(tid).ok_or(LinuxError::EPERM)?;
    thread_data.signal.send_signal(sig);
    Ok(())
}
pub fn send_signal_process(pid: Pid, sig: SignalInfo) -> LinuxResult<()> {
    info!("Send signal {:?} to process {}", sig.signo(), pid);
    let process_data = get_process_data(pid).ok_or(LinuxError::EPERM)?;
    process_data.signal.send_signal(sig);
    Ok(())
}
pub fn send_signal_process_group(pgid: Pid, sig: SignalInfo) -> usize {
    info!("Send signal {:?} to process group {}", sig.signo(), pgid);
    let mut count = 0;
    let Some(pg) = get_process_group(pgid) else {
        return 0;
    };
    for process in pg.get_processes() {
        count += send_signal_process(process.get_pid(), sig.clone()).is_ok() as usize;
    }
    count
}

fn make_siginfo(signo: u32, code: u32) -> LinuxResult<Option<SignalInfo>> {
