    /// permissions for sys_mmap
    ///
    /// See <https://github.com/bminor/glibc/blob/master/bits/mman.h>
    #[derive(Debug)]
    struct MmapProt: u32 {
        /// Page can be read.
        const PROT_READ = PROT_READ;
        /// Page can be written.
        const PROT_WRITE = PROT_WRITE;
        /// Page can be executed.
        const PROT_EXEC = PROT_EXEC;
