#[syscall_trace]
pub fn sys_brk(addr: usize) -> LinuxResult<isize> {
    let mut return_val: isize = current_process_data().get_heap_top() as isize;
    let heap_bottom = current_process_data().get_heap_bottom();
    if addr != 0 && addr >= heap_bottom && addr <= heap_bottom + axconfig::plat::USER_HEAP_SIZE {
        current_process_data().set_heap_top(addr);
        return_val = addr as isize;
    }
    Ok(return_val)
}

use arceos_posix_api::config::plat::PHYS_VIRT_OFFSET;
use axerrno::LinuxError;
use axhal::mem::VirtAddr;
use axhal::paging::MappingFlags;
use axhal::trap::{PAGE_FAULT, register_trap_handler};
use axsignal::{SignalInfo, Signo};
use linux_raw_sys::general::SI_KERNEL;
use starry_core::mm::is_accessing_user_memory;
use starry_core::task::{current_process, current_process_data};
use ourkernel2026_api::imp::task::signal::send_signal_process;
use ourkernel2026_api::imp::task::sys_exit_impl;

#[register_trap_handler(PAGE_FAULT)]
fn handle_page_fault(vaddr: VirtAddr, access_flags: MappingFlags, is_user: bool) -> bool {
    if vaddr.as_usize() > PHYS_VIRT_OFFSET {
        error!(
            "Kernel page fault at {:#x}, access_flags: {:#x?}",
            vaddr, access_flags
        );
        return false;
    }
    if !is_user && !is_accessing_user_memory() {
        warn!(
            "Maybe we are accessing user memory in kernel, and triggered a page fault at {:#x}, access_flags: {:#x?}",
            vaddr, access_flags
        );
    }

    if !current_process_data()
        .addr_space
        .lock()
        .handle_page_fault(vaddr, access_flags)
    {
        warn!(
            "{}: segmentation fault at {:#x}, access_flags: {:#x?}, send SIGSEGV.",
            axtask::current().id_name(),
            vaddr,
            access_flags,
        );
        if send_signal_process(
            current_process().get_pid(),
            SignalInfo::new(Signo::SIGSEGV, SI_KERNEL as _),
        )
        .is_err()
        {
            error!("send SIGSEGV failed");
            sys_exit_impl(LinuxError::EFAULT as _, Signo::SIGSEGV as _, false);
        }
    }
    true
}

