fn new_futex() -> Arc<WaitQueue> {
    Arc::new(WaitQueue::new())
}

const FUTEX_SIGNAL_POLL_INTERVAL: Duration = Duration::from_millis(10);

fn futex_value_changed(uaddr: &UserInPtr<u32>, value: u32) -> bool {
    uaddr.get_as_ref().map(|val| *val != value).unwrap_or(true)
}

fn futex_value_changed_or_signal(uaddr: &UserInPtr<u32>, value: u32) -> bool {
    futex_value_changed(uaddr, value) || has_unblocked_pending_signal()
}

fn wait_futex_interruptible(
    wq: &WaitQueue,
    uaddr: &UserInPtr<u32>,
    value: u32,
    timeout: Option<Duration>,
) -> LinuxResult<()> {
    if let Some(timeout) = timeout {
        let deadline = axhal::time::wall_time() + timeout;
        loop {
            if futex_value_changed(uaddr, value) {
                return Ok(());
            }
            if has_unblocked_pending_signal() {
                return Err(LinuxError::EINTR);
            }

            let now = axhal::time::wall_time();
            if now >= deadline {
                return Err(LinuxError::ETIMEDOUT);
            }
            let wait = core::cmp::min(deadline - now, FUTEX_SIGNAL_POLL_INTERVAL);
            wq.wait_timeout_until(wait, || futex_value_changed_or_signal(uaddr, value));
        }
    } else {
        loop {
            if futex_value_changed(uaddr, value) {
                return Ok(());
            }
            if has_unblocked_pending_signal() {
                return Err(LinuxError::EINTR);
            }
            wq.wait_timeout_until(FUTEX_SIGNAL_POLL_INTERVAL, || {
                futex_value_changed_or_signal(uaddr, value)
            });
        }
    }
}

#[syscall_trace]
pub fn sys_futex(
    uaddr: UserInPtr<u32>,
    futex_op: u32,
    value: u32,
    timeout: UserInPtr<timespec>,
    uaddr2: UserInPtr<u32>,
    value3: u32,
) -> LinuxResult<isize> {
    info!("futex {:?} {} {}", uaddr.address(), futex_op, value);

    let futex_table = &current_process_data().futex_table;

    let addr = uaddr.address().as_usize();
    let command = futex_op & (FUTEX_CMD_MASK as u32);
    match command {
        FUTEX_WAIT => {
            let observed = *uaddr.get_as_ref()?;
            if observed != value {
                return Err(LinuxError::EAGAIN);
            }
            let wq = futex_table
                .lock()
                .entry(addr)
                .or_insert_with(new_futex)
                .clone();

            let timeout = if !timeout.is_null() {
                Some(timespec_to_timevalue(*timeout.get_as_ref()?))
            } else {
                None
            };
            wait_futex_interruptible(&wq, &uaddr, value, timeout)?;

            Ok(0)
        }
        FUTEX_WAKE => {
            let wq = futex_table.lock().get(&addr).cloned();
            let mut count = 0;
            if let Some(wq) = wq {
                for _ in 0..value {
                    if !wq.notify_one(false) {
                        break;
                    }
                    count += 1;
                }
            }
            axtask::yield_now();
            Ok(count)
        }
        FUTEX_REQUEUE | FUTEX_CMP_REQUEUE => {
            if command == FUTEX_CMP_REQUEUE && *uaddr.get_as_ref()? != value3 {
                return Err(LinuxError::EAGAIN);
            }
            let value2 = timeout.address().as_usize() as u32;

            let mut futex_table = futex_table.lock();
            let wq = futex_table.get(&addr).cloned();
            let wq2 = futex_table
                .entry(uaddr2.address().as_usize())
                .or_insert_with(new_futex)
                .clone();
            drop(futex_table);

            let mut count = 0;
            if let Some(wq) = wq {
                for _ in 0..value {
                    if !wq.notify_one(false) {
                        break;
                    }
                    count += 1;
                }
                count += wq.requeue(value2 as usize, &wq2) as isize;
            }
            Ok(count)
        }
        FUTEX_WAIT_BITSET => {
            let bitset = value3;
            // TODO: Implement bitset support
            if bitset != FUTEX_BITSET_MATCH_ANY {
                warn!(
                    "[sys_futex] FUTEX_WAIT_BITSET does not support bitset except FUTEX_BITSET_MATCH_ANY yet."
                );
                return Err(LinuxError::ENOSYS);
            }
            let observed = *uaddr.get_as_ref()?;
            if observed != value {
                return Err(LinuxError::EAGAIN);
            }
            let wq = futex_table
                .lock()
                .entry(addr)
                .or_insert_with(new_futex)
                .clone();

            let timeout = if !timeout.is_null() {
                Some(timespec_to_timevalue(*timeout.get_as_ref()?))
            } else {
                None
            };
            wait_futex_interruptible(&wq, &uaddr, value, timeout)?;
            Ok(0)
        }
        FUTEX_WAKE_BITSET => {
            let bitset = value3;
            // TODO: Implement bitset support
            if bitset != FUTEX_BITSET_MATCH_ANY {
                warn!(
                    "[sys_futex] FUTEX_WAIT_BITSET does not support bitset except FUTEX_BITSET_MATCH_ANY yet."
                );
                return Err(LinuxError::ENOSYS);
            }
            let wq = futex_table.lock().get(&addr).cloned();
            let mut count = 0;
            if let Some(wq) = wq {
                for _ in 0..value {
                    if !wq.notify_one(false) {
                        break;
                    }
                    count += 1;
                }
            }
            axtask::yield_now();
            Ok(count)
        }
        _ => {
            warn!("[sys_futex] unknown command: {}", command);
            Err(LinuxError::ENOSYS)
        }
    }
}

