#[derive(Copy, Clone, PartialEq)]
enum RingBufferStatus {
    Full,
    Empty,
    Normal,
}

pub const PIPE_MAX_SIZE: usize = 65536;

const RING_BUFFER_SIZE: usize = PIPE_MAX_SIZE;

pub struct PipeRingBuffer {
    arr: [u8; RING_BUFFER_SIZE],
    head: usize,
    tail: usize,
    status: RingBufferStatus,
}

impl PipeRingBuffer {
    pub const fn new() -> Self {
        Self {
            arr: [0; RING_BUFFER_SIZE],
            head: 0,
            tail: 0,
            status: RingBufferStatus::Empty,
        }
    }

    pub fn write_byte(&mut self, byte: u8) {
        self.status = RingBufferStatus::Normal;
        self.arr[self.tail] = byte;
        self.tail = (self.tail + 1) % RING_BUFFER_SIZE;
        if self.tail == self.head {
            self.status = RingBufferStatus::Full;
        }
    }

    pub fn read_byte(&mut self) -> u8 {
        self.status = RingBufferStatus::Normal;
        let c = self.arr[self.head];
        self.head = (self.head + 1) % RING_BUFFER_SIZE;
        if self.head == self.tail {
            self.status = RingBufferStatus::Empty;
        }
        c
    }

    /// Get the length of remaining data in the buffer
    pub const fn available_read(&self) -> usize {
        if matches!(self.status, RingBufferStatus::Empty) {
            0
        } else if self.tail > self.head {
            self.tail - self.head
        } else {
            self.tail + RING_BUFFER_SIZE - self.head
        }
    }

    /// Get the length of remaining space in the buffer
    pub const fn available_write(&self) -> usize {
        if matches!(self.status, RingBufferStatus::Full) {
            0
        } else {
            RING_BUFFER_SIZE - self.available_read()
        }
    }
}

pub struct PipeShared {
    buffer: Mutex<PipeRingBuffer>,
    readers: AtomicUsize,
    writers: AtomicUsize,
}

pub struct Pipe {
    readable: bool,
    shared: Arc<PipeShared>,
    inode: u64,
    file_flags: Mutex<FileFlags>,
}

impl Pipe {
    pub fn new(file_flags: FileFlags) -> (Pipe, Pipe) {
        let shared = Arc::new(PipeShared {
            buffer: Mutex::new(PipeRingBuffer::new()),
            readers: AtomicUsize::new(1),
            writers: AtomicUsize::new(1),
        });
        let inode = random_u32();
        let read_end = Pipe {
            readable: true,
            shared: shared.clone(),
            inode: inode as _,
            file_flags: Mutex::new(file_flags | FileFlags::READ),
        };
        let write_end = Pipe {
            readable: false,
            shared,
            inode: inode as _,
            file_flags: Mutex::new(file_flags | FileFlags::WRITE),
        };
        (read_end, write_end)
    }

    pub const fn readable(&self) -> bool {
        self.readable
    }

    pub const fn writable(&self) -> bool {
        !self.readable
    }

    pub fn write_end_close(&self) -> bool {
        self.shared.writers.load(Ordering::Acquire) == 0
    }

    pub fn read_end_close(&self) -> bool {
        self.shared.readers.load(Ordering::Acquire) == 0
    }

    pub fn is_non_block(&self) -> bool {
        self.file_flags.lock().contains(FileFlags::NON_BLOCK)
    }
}

impl Drop for Pipe {
    fn drop(&mut self) {
        if self.readable {
            self.shared.readers.fetch_sub(1, Ordering::AcqRel);
        } else {
            self.shared.writers.fetch_sub(1, Ordering::AcqRel);
        }
    }
}

impl FileLike for Pipe {
    fn read(&self, buf: &mut [u8]) -> LinuxResult<usize> {
        if !self.readable() {
            return Err(LinuxError::EPERM);
        }
        let mut read_size = 0usize;
        let max_len = buf.len();
        let is_non_block = self.is_non_block();
        loop {
            let mut ring_buffer = self.shared.buffer.lock();
            let loop_read = ring_buffer.available_read();
            if loop_read == 0 {
                if self.write_end_close() || read_size > 0 {
                    return Ok(read_size);
                }
                // write end is open but the pipe is empty
                if is_non_block {
                    return Err(LinuxError::EAGAIN);
                }
                drop(ring_buffer);
                // Data not ready, wait for write end
                // TODO: interruptable wait
                task_yield_interruptable()?;
                continue;
            }
            for _ in 0..loop_read {
                if read_size == max_len {
                    return Ok(read_size);
                }
                buf[read_size] = ring_buffer.read_byte();
                read_size += 1;
            }
        }
    }

    fn write(&self, buf: &[u8]) -> LinuxResult<usize> {
        if !self.writable() {
            return Err(LinuxError::EPERM);
        }
        let mut write_size = 0usize;
        let max_len = buf.len();
        let is_non_block = self.is_non_block();
        loop {
            if self.read_end_close() {
                return if write_size > 0 {
                    Ok(write_size)
                } else {
                    Err(LinuxError::EPIPE)
                };
            }

            let mut ring_buffer = self.shared.buffer.lock();
            let loop_write = ring_buffer.available_write();
            // non-blocking write to pipe
            // 如果请求写入的字节数 n<= PIPE_BUF：write会立即返回失败，设置 errno = EAGAIN。
            // 如果 n> PIPE_BUF：write会尽力写入管道当前能容纳的最大连续空间 k（k>= 1），并返回实际写入的字节数 k。如果管道当前已完全满，连一个字节都写不进去，则立即返回失败，设置 errno = EAGAIN。
            if is_non_block && loop_write < max_len {
                if max_len <= RING_BUFFER_SIZE {
                    return Err(LinuxError::EAGAIN);
                } else {
                    if loop_write == 0 {
                        return Err(LinuxError::EAGAIN);
                    }
                    for _ in 0..loop_write {
                        ring_buffer.write_byte(buf[write_size]);
                        write_size += 1;
                    }
                    return Ok(write_size);
                }
            }
            if loop_write == 0 {
                drop(ring_buffer);
                // Buffer is full, wait for read end to consume
                task_yield_interruptable()?;
                continue;
            }
            for _ in 0..loop_write {
                if write_size == max_len {
                    return Ok(write_size);
                }
                ring_buffer.write_byte(buf[write_size]);
                write_size += 1;
            }
        }
    }

    fn status(&self) -> LinuxResult<Metadata> {
        // TODO: uid, gid, etc.
        Ok(Metadata {
            inode: self.inode,
            n_link: 1,
            mode: NodePermission::OWNER_READ | NodePermission::OWNER_WRITE,
            node_type: NodeType::Fifo,
            uid: 1000,
            gid: 1000,
            block_size: 4096,
            ..Default::default()
        })
    }

    fn poll(&self) -> LinuxResult<PollState> {
        let buf = self.shared.buffer.lock();
        Ok(PollState {
            readable: self.readable() && (buf.available_read() > 0 || self.write_end_close()),
            writable: self.writable() && buf.available_write() > 0 && !self.read_end_close(),
        })
    }

    fn get_flags(&self) -> FileFlags {
        *self.file_flags.lock()
    }

    fn set_flags(&self, flags: FileFlags) {
        *self.file_flags.lock() = flags;
    }

    fn into_any(self: Arc<Self>) -> Arc<dyn Any + Send + Sync> {
        self
    }

    fn type_mismatch_error(&self) -> LinuxError
    where
        Self: Sized + 'static,
    {
        LinuxError::ESPIPE
    }
}

