fn timespec_to_duration(ts: timespec) -> LinuxResult<Duration> {
    if ts.tv_sec < 0 || ts.tv_nsec < 0 || ts.tv_nsec >= 1_000_000_000 {
        return Err(LinuxError::EINVAL);
    }
    Ok(Duration::new(ts.tv_sec as u64, ts.tv_nsec as u32))
}

fn duration_to_timespec(duration: Duration) -> timespec {
    timespec {
        tv_sec: duration.as_secs() as _,
        tv_nsec: duration.subsec_nanos() as _,
    }
}

fn remaining_spec(timer: &PosixTimer) -> itimerspec {
    let now = axhal::time::monotonic_time();
    let remaining = timer
        .next_expiration
        .map(|deadline| {
            if deadline <= now {
                Duration::ZERO
            } else {
                deadline - now
            }
        })
        .unwrap_or(Duration::ZERO);

    itimerspec {
        it_interval: duration_to_timespec(timer.interval),
        it_value: duration_to_timespec(remaining),
    }
}

fn deliver_timer_signal(timer: PosixTimer) {
    if timer.notify == SIGEV_NONE as c_int || timer.signal == 0 {
        return;
    }

    let Ok(signo) = parse_timer_signo(timer.signal) else {
        return;
    };
    let sig = SignalInfo::new(signo, SI_TIMER as _);
    if timer.notify == SIGEV_THREAD_ID as c_int {
        if let Some(tid) = timer.target_tid {
            let _ = send_signal_thread(tid, sig);
        }
    } else {
        let _ = send_signal_process(timer.owner_pid, sig);
    }
}

fn spawn_posix_timer_task(timer_id: i32, generation: u64) {
    let _ = axtask::spawn(move || {
        loop {
            let sleep_for = {
                let timers = POSIX_TIMERS.lock();
                let Some(timer) = timers.get(&timer_id) else {
                    return;
                };
                if timer.generation != generation {
                    return;
                }
                let Some(deadline) = timer.next_expiration else {
                    return;
                };
                let now = axhal::time::monotonic_time();
                if deadline <= now {
                    Duration::ZERO
                } else {
                    deadline - now
                }
            };

            if !sleep_for.is_zero() {
                axtask::sleep(sleep_for);
            }

            let (expired_timer, should_continue) = {
                let mut timers = POSIX_TIMERS.lock();
                let Some(timer) = timers.get_mut(&timer_id) else {
                    return;
                };
                if timer.generation != generation {
                    return;
                }
                let Some(deadline) = timer.next_expiration else {
                    return;
                };
                let now = axhal::time::monotonic_time();
                if deadline > now {
                    continue;
                }

                let expired = *timer;
                if timer.interval.is_zero() {
                    timer.next_expiration = None;
                    (expired, false)
                } else {
                    let mut next = deadline + timer.interval;
                    while next <= now {
                        next += timer.interval;
                    }
                    timer.next_expiration = Some(next);
                    (expired, true)
                }
            };

            deliver_timer_signal(expired_timer);
            if !should_continue {
                return;
            }
        }
    });
}

