#[syscall_trace]
pub fn sys_nanosleep(
    requested: UserInPtr<TimeSpec>,
    remain: UserOutPtr<TimeSpec>,
) -> LinuxResult<isize> {
    let duration = requested.get_as_ref()?.to_duration()?;
    let now = axhal::time::monotonic_time();
    if let Err(LinuxError::EINTR) = task_sleep_interruptable(duration) {
        if let Ok(remain) = remain.get_as_mut_ref() {
            let after = axhal::time::monotonic_time();
            let elapsed = if after >= now { after - now } else { Duration::ZERO };
            *remain = duration.saturating_sub(elapsed).into();
        }
        return Err(LinuxError::EINTR);
    }
    Ok(0)
}

#[syscall_trace]
pub fn sys_clock_nanosleep(
    clock_id: u32,
    flags: c_int,
    requested: UserInPtr<TimeSpec>,
    remain: UserOutPtr<TimeSpec>,
) -> LinuxResult<isize> {
    if clock_id != CLOCK_MONOTONIC {
        debug!("[sys_clock_nanosleep] Unsupported clock_id: {}", clock_id);
    }
    if flags & !TIMER_ABSTIME != 0 {
        return Err(LinuxError::EINVAL);
    }

    if flags & TIMER_ABSTIME != 0 {
        let deadline = requested.get_as_ref()?.to_duration()?;
        let now = axhal::time::monotonic_time();
        if deadline <= now {
            return Ok(0);
        }
        let sleep_for = deadline - now;
        if let Err(LinuxError::EINTR) = task_sleep_interruptable(sleep_for) {
            return Err(LinuxError::EINTR);
        }
        return Ok(0);
    }

    sys_nanosleep(requested.clone(), remain.clone())
}

