        // SAFETY: c_char is u8
        let slice = unsafe { mem::transmute::<&[c_char], &[u8]>(slice) };

        str::from_utf8(slice).map_err(|_| LinuxError::EILSEQ)
    }

    pub fn fmt_trace_as_str(&self) -> String {
        match self.get_as_str() {
